import org.junit.jupiter.api.Test;

/**
 * Property-driven soak variant of {@link FuzzSmokeTest}. Excluded from default JDK-25 builds by the repo's
 * {@code skipSlowTests} profile; run it with:
 *
 * <pre>
 * mvn -o -Dmaven.repo.local=.m2_repo -pl core/queryalgebra/equivalence test \
 *     -P slowTestsOnly,\!skipSlowTests -Dtest=FuzzSoakTest \
 *     -Dequivalence.fuzz.iterations=5000 -Dequivalence.fuzz.seed=42 -Dequivalence.fuzz.timeBudgetSeconds=900
 * </pre>
 *
 * System properties: {@code equivalence.fuzz.iterations} (random pairs, default 2000), {@code equivalence.fuzz.seed}
 * (default nanoTime, always printed), {@code equivalence.fuzz.timeBudgetSeconds} (default 300),
 * {@code equivalence.fuzz.corpus} ({@code scope-safety} default, {@code none} to disable),
 * {@code equivalence.fuzz.artifactDir} (default target/equivalence-fuzz).
 */
@Tag("slow")
class FuzzSoakTest {

	@Test
	void soak() {
		// Deterministic default: this test runs in the pr-verify slow-tests job, and a random
		// default seed would turn latent bugs into nondeterministic CI failures on unrelated PRs.
		// Pass -Dequivalence.fuzz.seed explicitly for exploratory campaigns.
		long seed = Long.getLong("equivalence.fuzz.seed", 20260716L);
		int iterations = Integer.getInteger("equivalence.fuzz.iterations", 2000);
		int timeBudgetSeconds = Integer.getInteger("equivalence.fuzz.timeBudgetSeconds", 300);
		String corpus = System.getProperty("equivalence.fuzz.corpus", "scope-safety");
		Path artifactDir = Path.of(System.getProperty("equivalence.fuzz.artifactDir", "target/equivalence-fuzz"));
		System.out.println("[fuzz] soak seed=" + seed + " iterations=" + iterations
				+ " timeBudgetSeconds=" + timeBudgetSeconds + " corpus=" + corpus);

		DifferentialFuzzHarness harness = new DifferentialFuzzHarness(
				FuzzProfile.primary(96),
				FuzzProfile.secondary(96),
				new PairShrinker(),
				new FuzzArtifactWriter(artifactDir, seed),
				true);

		List<TreePair> pairs = new ArrayList<>();
		if (!"none".equals(corpus)) {
			CorpusQuerySource corpusSource = new CorpusQuerySource();
			pairs.addAll(corpusSource.pairs(seed, 4));
			System.out.println("[fuzz] corpus pairs=" + pairs.size()
					+ " skippedQueries=" + corpusSource.skippedQueries());
			assertTrue(!pairs.isEmpty(),
					"scope-safety corpus produced no pairs — the rdf4j-sail-testsuite resources are "
							+ "missing or unparseable, silently losing the curated adversarial coverage");
			List<TupleExpr> optimizerSeeds = new ArrayList<>();
			RandomTreeGenerator generator = new RandomTreeGenerator();
			for (int i = 0; i < 25; i++) {
				optimizerSeeds.add(generator.generate(seed + 100_000L + i));
			}
			pairs.addAll(new LegacyOptimizerPairSource().pairs(seed, optimizerSeeds));
		}
		pairs.addAll(new RandomTreePairSource().pairs(seed, iterations));

		FuzzRunSummary summary = harness.run(seed, pairs, Duration.ofSeconds(timeBudgetSeconds));
		System.out.println(summary.report());
		assertEquals(pairs.size(), summary.pairCount(),
				"time budget truncated the soak campaign; partial campaigns are failures");
		assertTrue(summary.violations().isEmpty(),
				() -> "differential invariant violations (artifacts under " + artifactDir + "):\n" + summary.report());
	}
}
